const alert = $input.first().json;

// Generar número de ticket único
const ticketNumber = 'TICKET-' + 
  new Date().getFullYear().toString().slice(-2) + 
  ('0' + (new Date().getMonth() + 1)).slice(-2) + 
  ('0' + new Date().getDate()).slice(-2) + 
  '-' + 
  Math.random().toString(36).substr(2, 6).toUpperCase();

// Determinar prioridad
function getPriority(severity, riskScore) {
  if (severity === 'critical' || riskScore >= 80) return 'high';
  if (severity === 'high' || riskScore >= 60) return 'medium';
  return 'low';
}

// Determinar categoría
function getCategory(ruleName) {
  const rule = ruleName.toLowerCase();
  if (rule.includes('ssh') || rule.includes('login')) return 'Authentication';
  if (rule.includes('sql') || rule.includes('injection')) return 'Web Attack';
  if (rule.includes('scan') || rule.includes('port')) return 'Reconnaissance';
  if (rule.includes('malware') || rule.includes('virus')) return 'Malware';
  return 'General Security';
}

// Determinar asignación automática
function getAssignment(category, severity) {
  const assignments = {
    'Authentication': 'soc_team@example.com',
    'Web Attack': 'websec_team@example.com',
    'Reconnaissance': 'monitoring_team@example.com',
    'Malware': 'malware_team@example.com'
  };

  return assignments[category] || 'security_team@example.com';
}

const ticketData = {
  ticket_number: ticketNumber,
  title: alert.title || `[${alert.severity}] ${alert.rule_name}`,
  description: alert.description || 'Sin descripción',
  status: 'open',
  priority: getPriority(alert.severity, alert.risk_score),
  category: getCategory(alert.rule_name),
  source_ip: alert.source_ip,
  threat_score: alert.risk_score || 0,
  assigned_to: getAssignment(getCategory(alert.rule_name), alert.severity),
  created_at: new Date().toISOString(),
  alert_reference: {
    rule_name: alert.rule_name,
    severity: alert.severity,
    timestamp: alert.timestamp
  }
};

return [{ json: ticketData }];

const ticket = $input.first().json;

// Enviar también a Logstash para registro centralizado
try {
  await $http.post({
    url: 'http://logstash:8081',
    body: {
      ...ticket,
      type: 'ticket_created',
      source: 'n8n_ticket_system',
      timestamp: new Date().toISOString()
    },
    headers: { 'Content-Type': 'application/json' }
  });
} catch (error) {
  console.log('Error enviando ticket a Logstash:', error.message);
}

// Generar respuesta
const response = {
  success: true,
  ticket_number: ticket.ticket_number,
  message: `Ticket ${ticket.ticket_number} creado exitosamente`,
  details: {
    priority: ticket.priority,
    category: ticket.category,
    assigned_to: ticket.assigned_to,
    timestamp: new Date().toISOString()
  }
};

return [{ json: response }];
